import{_ as d,o as e,c as r,ai as o}from"./chunks/framework.CaiDwmc7.js";const y=JSON.parse('{"title":"Styling Reference","description":"Color palette, spectrum gradient, workflow phase colors, component styles, icons, and Nerd Font glyphs.","frontmatter":{"title":"Styling Reference","description":"Color palette, spectrum gradient, workflow phase colors, component styles, icons, and Nerd Font glyphs.","outline":[2,3]},"headers":[],"relativePath":"cli/styling.md","filePath":"cli/styling.md","lastUpdated":1772487797000}'),c={name:"cli/styling.md"};function a(l,t,n,i,s,h){return e(),r("div",null,[...t[0]||(t[0]=[o(`<h1 id="styling-reference" tabindex="-1">Styling Reference <a class="header-anchor" href="#styling-reference" aria-label="Permalink to “Styling Reference”">​</a></h1><h2 id="color-palette" tabindex="-1">Color Palette <a class="header-anchor" href="#color-palette" aria-label="Permalink to “Color Palette”">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>Hex</th><th>Usage</th></tr></thead><tbody><tr><td>Primary</td><td><code>#7C3AED</code></td><td>Purple — Titles, active items, header bg, focused borders</td></tr><tr><td>Secondary</td><td><code>#2c2d3a</code></td><td>Editor bg — Inactive elements, tab bar inactive bg</td></tr><tr><td>Success</td><td><code>#10B981</code></td><td>Green — Completed items, success logs</td></tr><tr><td>Warning</td><td><code>#F59E0B</code></td><td>Amber — Blocked items, warnings, paused state</td></tr><tr><td>Error</td><td><code>#EF4444</code></td><td>Red — Error messages, error state</td></tr><tr><td>Info</td><td><code>#3B82F6</code></td><td>Blue — Info logs, panel titles</td></tr><tr><td>Dim</td><td><code>#6B7280</code></td><td>Gray — Borders, pending items, hints</td></tr><tr><td>Background</td><td><code>#1F2937</code></td><td>Dark gray — Background elements, modal bg</td></tr><tr><td>White</td><td><code>#FFFFFF</code></td><td>White — Header text</td></tr><tr><td>BorderNormal</td><td><code>#4B5563</code></td><td>Inactive borders</td></tr><tr><td>BorderActive</td><td><code>= Primary</code></td><td>Focused borders</td></tr><tr><td>Highlight</td><td><code>#06B6D4</code></td><td>Cyan — Current activity, highlighted text</td></tr></tbody></table><h2 id="spectrum-gradient-4-stop" tabindex="-1">Spectrum Gradient (4-Stop) <a class="header-anchor" href="#spectrum-gradient-4-stop" aria-label="Permalink to “Spectrum Gradient (4-Stop)”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>#3B82F6 ───▶ #14B8A6 ───▶ #22C55E ───▶ #F59E0B</span></span>
<span class="line"><span> Blue          Teal         Green        Amber</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Used for: Progress bar fill, ASCII logo, prism rays, sidebar logo, gradient bar.</p><h2 id="workflow-phase-colors" tabindex="-1">Workflow Phase Colors <a class="header-anchor" href="#workflow-phase-colors" aria-label="Permalink to “Workflow Phase Colors”">​</a></h2><table tabindex="0"><thead><tr><th>Phase</th><th>Color</th><th>Hex</th></tr></thead><tbody><tr><td>Research</td><td>Blue</td><td><code>#3B82F6</code></td></tr><tr><td>Plan</td><td>Teal</td><td><code>#14B8A6</code></td></tr><tr><td>Implement</td><td>Green</td><td><code>#22C55E</code></td></tr><tr><td>Validate</td><td>Amber</td><td><code>#F59E0B</code></td></tr><tr><td>Idle</td><td>Gray</td><td><code>#4B5563</code></td></tr></tbody></table><h2 id="component-styles" tabindex="-1">Component Styles <a class="header-anchor" href="#component-styles" aria-label="Permalink to “Component Styles”">​</a></h2><table tabindex="0"><thead><tr><th>Style</th><th>Properties</th></tr></thead><tbody><tr><td><code>TitleStyle</code></td><td>Bold, FG: Purple <code>#7C3AED</code>, Padding(0,1)</td></tr><tr><td><code>HeaderStyle</code></td><td>Bold, FG: White, BG: Purple <code>#7C3AED</code>, Padding(0,1), MarginBottom(1)</td></tr><tr><td><code>PanelStyle</code></td><td>Border: Rounded, BorderFG: Gray <code>#6B7280</code>, Padding(0,1)</td></tr><tr><td><code>StoriesTitleStyle</code></td><td>Bold, FG: Blue <code>#3B82F6</code></td></tr><tr><td><code>ActivityTitleStyle</code></td><td>Bold, FG: Teal <code>#14B8A6</code></td></tr><tr><td><code>LogTitleStyle</code></td><td>Bold, FG: Green <code>#22C55E</code></td></tr><tr><td><code>CompleteStyle</code></td><td>FG: Green <code>#10B981</code></td></tr><tr><td><code>CurrentStyle</code></td><td>Bold, FG: Purple <code>#7C3AED</code></td></tr><tr><td><code>PendingStyle</code></td><td>FG: Gray <code>#6B7280</code></td></tr><tr><td><code>BlockedStyle</code></td><td>Italic, FG: Amber <code>#F59E0B</code></td></tr><tr><td><code>HighlightStyle</code></td><td>FG: Cyan <code>#06B6D4</code></td></tr><tr><td><code>DimStyle</code></td><td>FG: Gray <code>#6B7280</code></td></tr><tr><td><code>ErrorStyle</code></td><td>Bold, FG: Red <code>#EF4444</code></td></tr><tr><td><code>StatusBarStyle</code></td><td>FG: Gray <code>#6B7280</code>, Padding(0,1)</td></tr><tr><td><code>SidebarStyle</code></td><td>Border: Rounded, BorderFG: Purple <code>#7C3AED</code>, Padding(0,1)</td></tr><tr><td><code>SidebarBrandStyle</code></td><td>Bold, FG: Purple <code>#7C3AED</code></td></tr><tr><td><code>SidebarTitleStyle</code></td><td>FG: White <code>#FFFFFF</code></td></tr><tr><td><code>AppHeaderStyle</code></td><td>Bold, FG: White, BG: Purple <code>#7C3AED</code>, Padding(0,1)</td></tr><tr><td><code>FooterStyle</code></td><td>FG: Gray <code>#6B7280</code>, Padding(0,1)</td></tr></tbody></table><h2 id="icons" tabindex="-1">Icons <a class="header-anchor" href="#icons" aria-label="Permalink to “Icons”">​</a></h2><table tabindex="0"><thead><tr><th>Icon</th><th>Character</th><th>Color</th><th>Usage</th></tr></thead><tbody><tr><td>Check</td><td><code>✓</code></td><td>Green <code>#10B981</code></td><td>Completed stories</td></tr><tr><td>Play</td><td><code>▸</code></td><td>Purple <code>#7C3AED</code></td><td>Active story, running state</td></tr><tr><td>Pending</td><td><code>○</code></td><td>Gray <code>#6B7280</code></td><td>Pending stories</td></tr><tr><td>Blocked</td><td><code>⊘</code></td><td>Amber <code>#F59E0B</code></td><td>Blocked stories</td></tr><tr><td>Error</td><td><code>✗</code></td><td>Red <code>#EF4444</code></td><td>Failed items</td></tr></tbody></table><h2 id="nerd-font-icons" tabindex="-1">Nerd Font Icons <a class="header-anchor" href="#nerd-font-icons" aria-label="Permalink to “Nerd Font Icons”">​</a></h2><p>When Nerd Font is detected, the following glyphs are used for tab bar, sidebar, and footer:</p><table tabindex="0"><thead><tr><th>Context</th><th>Nerd Font</th><th>ASCII Fallback</th></tr></thead><tbody><tr><td>Separator (right)</td><td><code>\\uE0BC</code></td><td><code>▶</code></td></tr><tr><td>Separator (left)</td><td><code>\\uE0BA</code></td><td><code>◀</code></td></tr><tr><td>Home</td><td><code>\\uF015</code></td><td><code>1</code></td></tr><tr><td>Search</td><td><code>\\uF002</code></td><td><code>2</code></td></tr><tr><td>List</td><td><code>\\uF03A</code></td><td><code>3</code></td></tr><tr><td>Bolt</td><td><code>\\uF0E7</code></td><td><code>4</code></td></tr><tr><td>Folder</td><td><code>\\uF07B</code></td><td><code>5</code></td></tr><tr><td>Git Branch</td><td><code>\\uE0A0</code></td><td><code>6</code></td></tr><tr><td>User</td><td><code>\\uF007</code></td><td><code>7</code></td></tr><tr><td>Chart</td><td><code>\\uF080</code></td><td><code>8</code></td></tr><tr><td>Grid</td><td><code>\\uF009</code></td><td><code>9</code></td></tr></tbody></table><h2 id="theme-override-system" tabindex="-1">Theme Override System <a class="header-anchor" href="#theme-override-system" aria-label="Permalink to “Theme Override System”">​</a></h2><p>When running in an IDE terminal, detected accent and editor background colors override the defaults:</p><ul><li><code>ApplyTheme(accentHex)</code> — Overrides <code>Primary</code>, rebuilds TitleStyle, HeaderStyle, CurrentStyle, ProgressBarStyle, SidebarStyle, SidebarBrandStyle, PlayIcon, AppHeaderStyle, TabBorderColor</li><li><code>ApplySecondary(editorBgHex)</code> — Overrides <code>Secondary</code> and <code>TabBarInactiveBg</code></li></ul>`,18)])])}const b=d(c,[["render",a]]);export{y as __pageData,b as default};
